double calculateTotal(
  double price, [
  double taxRate = 0.05,
  double discount = 0.0,
]) {
  double tax = price * taxRate;
  double discounted = price * discount;
  return price + tax - discounted;
}

void main() {
  print(calculateTotal(100.0));
  print(calculateTotal(100.0, 0.08, 0.1));
  print(calculateTotal(100.0, 0.1));
}
